const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');
const xml2js = require('xml2js');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload', upload.single('xmlFile'), (req, res) => {
  const filePath = req.file.path;

  fs.readFile(filePath, (err, data) => {
    if (err) {
      return res.status(500).send('Error reading file');
    }

    xml2js.parseString(data, { mergeAttrs: true }, (err, result) => {
      if (err) {
        return res.status(400).send('Error parsing XML');
      }

      // Process the parsed XML data
      console.log(result);

      res.send('XML processed successfully');
    });
  });
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});